package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

public class CSVFormatTest {

    @Test
    public void testWithFirstRecordAsHeader() {
        // Given
        CSVFormat csvFormat = Mockito.spy(CSVFormat.DEFAULT);

        // When
        CSVFormat result = csvFormat.withFirstRecordAsHeader();

        // Then
        assertTrue(result.getSkipHeaderRecord());
        assertNotNull(result.getHeader());
    }

    @Test
    public void testEquals() {
        // Given
        CSVFormat csvFormat1 = CSVFormat.DEFAULT;
        CSVFormat csvFormat2 = CSVFormat.EXCEL;

        // Then
        assertNotEquals(csvFormat1, csvFormat2);
    }

    @Test
    public void testWithFirstRecordAsHeaderReflection() {
        // Given
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        // When
        CSVFormat result = invokeMethod(csvFormat, "withFirstRecordAsHeader");

        // Then
        assertTrue(result.getSkipHeaderRecord());
        assertNotNull(result.getHeader());
    }

    private <T> T invokeMethod(Object obj, String methodName) {
        try {
            return (T) obj.getClass().getMethod(methodName).invoke(obj);
        } catch (Exception e) {
            throw new RuntimeException("Failed to invoke method: " + methodName, e);
        }
    }

